    s->lmc->sublen,
    (ZOPFLI_CACHE_LENGTH * (pos - s->blockstart) * 3
     + (ZOPFLI_CACHE_LENGTH - 1) * 3 + 3) * sizeof(*s->lmc->sublen)))
